SELECT synapse_id, length
FROM synapses
WHERE synapse_type = 'excitatory';

SELECT COUNT(*) 
FROM synapses 
WHERE status = 'active' AND confidence_score > 0.5;

SELECT COUNT(*) AS active_synapse_count
FROM synapses
WHERE status = 'active' AND dataset = 'Dataset1';

SELECT dataset
FROM synapses
WHERE confidence_score = (
  SELECT MAX(confidence_score) 
  FROM synapses
);

SELECT AVG(confidence_score) AS average_confidence_score
FROM synapses
WHERE dataset = 'Dataset A' AND length > 10;

SELECT synapse_id, length
FROM synapses
ORDER BY length DESC;
